// ============================================================
// CHỈ SỬA BLOCK NÀY — input từ node trước:
// REPO_ROOT, WORKSPACE, FACEBOOK_PAGE_ID,
// SCHEDULE_INTERVAL_HOURS, SCHEDULE_START
// ============================================================

// Ưu tiên lấy từ node trước, nếu không có thì fallback default
const REPO_ROOT = String($json.REPO_ROOT || '/repo').trim();
const WORKSPACE = String($json.WORKSPACE || '/workspace').trim();
const FACEBOOK_PAGE_ID = String($json.FACEBOOK_PAGE_ID || '61560996974889').trim();

let SCHEDULE_INTERVAL_HOURS = Number($json.SCHEDULE_INTERVAL_HOURS);
if (!Number.isFinite(SCHEDULE_INTERVAL_HOURS) || SCHEDULE_INTERVAL_HOURS <= 0) {
  SCHEDULE_INTERVAL_HOURS = 24;
}

const SCHEDULE_START = String(
  $json.SCHEDULE_START || '2026-05-02T22:00:00+07:00'
).trim();

// ============================================================
// Logic xử lý
// ============================================================

const winDrivePath = (p) =>
  /^[a-zA-Z]:[\\/]/.test(String(p || '').trim());

// Ưu tiên workspace từ input
let base_dir = WORKSPACE.trim();
base_dir = base_dir.replace(/[/\\]+$/, '');

const repoWin = winDrivePath(REPO_ROOT);
const baseWin = winDrivePath(base_dir);

if (repoWin !== baseWin) {
  throw new Error(
    'REPO_ROOT và WORKSPACE phải cùng kiểu Windows hoặc cùng Linux/Docker (/repo + /workspace). Không trộn D: với / trong container.'
  );
}

const norm = base_dir
  .replace(/\\/g, '/')
  .replace(/\/+$/, '');

const log_file = `${norm}/n8n_publish_run.jsonl`;

let hours = SCHEDULE_INTERVAL_HOURS;
let schedule_args = `--schedule-interval-hours ${hours}`;

let schedule_start = SCHEDULE_START;

if (schedule_start) {
  schedule_args += schedule_start.includes(' ')
    ? ` --schedule-start "${schedule_start.replace(/"/g, '')}"`
    : ` --schedule-start ${schedule_start}`;
}

return [
  {
    json: {
      workspace: base_dir,
      base_dir,
      repo_root: REPO_ROOT,
      log_file,
      facebook_page_id: FACEBOOK_PAGE_ID,
      schedule_interval_hours: hours,
      schedule_start,
      schedule_args,
    },
  },
];

const item = $input.first().json;
const cfg = $('2 Publishing config (sửa 1 lần trong Code)').first().json;
const text = item.stdout ?? item.text ?? '';
if (item.exitCode !== 0 && item.exitCode !== undefined) {
  throw new Error(item.stderr || `export failed (exit ${item.exitCode})`);
}
const parsed = JSON.parse(text || '{}');
if (!Array.isArray(parsed.jobs)) {
  throw new Error('Exporter JSON must contain a jobs array');
}
if (parsed.jobs.length === 0) {
  const bd = parsed.base_dir || cfg.base_dir || '';
  const c = parsed.count;
  const cnt = c === undefined ? '?' : String(c);
  throw new Error(
    'Exporter trả về 0 job (count=' + cnt + ', base_dir=' + bd + '). '
      + 'Không phải lỗi If/Switch: node sau chỉ chạy khi có ít nhất một job. Kiểm tra workspace hoặc volume Docker; session có đủ video, title, description, thumbnail không; có marker exported-posted không. '
      + 'Chạy ngoài n8n: export_publish_jobs.py đúng base_dir và thêm các cờ debug và audit.',
  );
}
const asBool = (v) => v === true || v === 'true' || v === 1 || v === '1';
return parsed.jobs.map((job) => ({
  json: {
    ...job,
    youtube_posted: asBool(job.youtube_posted),
    facebook_posted: asBool(job.facebook_posted),
    repo_root: cfg.repo_root,
    base_dir: cfg.base_dir,
    log_file: cfg.log_file,
    facebook_page_id: cfg.facebook_page_id,
  },
}));

const cur = $input.item;
const idx =
  typeof $input.itemIndex === 'number' && !Number.isNaN($input.itemIndex)
    ? $input.itemIndex
    : 0;
let rows = [];
try {
  rows = $('5 Split jobs (+ giữ config)').all();
} catch {
  rows = [];
}
let from5 = rows[idx]?.json;
if (!from5 && rows.length === 0) {
  if (idx !== 0) {
    throw new Error(
      '6b: thiếu .all() trên Split jobs khi có nhiều item — nâng n8n hoặc chỉ chạy 1 job mỗi lần.'
    );
  }
  from5 = $('5 Split jobs (+ giữ config)').first()?.json;
}
if (!from5 || typeof from5 !== 'object') {
  throw new Error('6b: không đọc được job từ Split jobs tại index ' + idx);
}
const overlay = cur.json && typeof cur.json === 'object' ? cur.json : {};
const merged = { ...from5, ...overlay };
for (const k of ['stdout', 'stderr', 'exitCode', 'text']) {
  if (merged[k] !== undefined && from5[k] === undefined) {
    delete merged[k];
  }
}
const p = String(merged.video_path || '').trim();
if (!p) {
  throw new Error(
    'Missing video_path sau 6 Log (pairing index=' + idx + '). session=' + String(merged.session_name || '?')
    ,
  );
}
merged.video_path = p.split(String.fromCharCode(92)).join('/');
return { json: merged, binary: cur.binary };

const raw = $('6b Carry job → Read').item?.json;
const job = raw != null && typeof raw === 'object' && !Array.isArray(raw) ? raw : {};
const rid = String(job.youtube_remote_id || '').trim();
if (!rid) {
  throw new Error(
    'youtube_posted=true nhưng thiếu youtube_remote_id trong job — kiểm tra posted_youtube.json có remote_id và chạy lại export (session_publish_jobs).'
    ,
  );
}
return { json: { ...job, id: rid }, binary: {} };

function parseIsoUtcMs(raw) {
  let sa = String(raw || '').trim();
  if (!sa) return NaN;
  if (!sa.includes('T') && sa.includes(' ')) sa = sa.replace(' ', 'T');
  sa = sa.replace(/(\d{2}:\d{2}:\d{2}\.\d{3})\d+/, '$1');
  return Date.parse(sa);
}
const item = $input.item;
if (item.json.error) {
  throw new Error('Read video (YouTube): ' + String(item.json.error));
}
if (!item.binary?.data) {
  throw new Error('Read video (YouTube): missing binary.data');
}
const meta = $('6b Carry job → Read').item?.json ?? {};
const sa = String(meta.scheduled_at || '').trim();
if (!sa) {
  throw new Error(
    'YouTube: scheduled_at trống — Studio coi là \"Riêng tư\" (không \"Đã lên lịch\"); kiểm tra exporter + node 6b.'
    ,
  );
}
const publishMs = parseIsoUtcMs(sa);
if (!Number.isFinite(publishMs)) {
  throw new Error(
    'YouTube: scheduled_at không parse được (ISO RFC3339, có offset ví dụ +07:00): ' + sa
    ,
  );
}
const skewMs = 5000;
if (publishMs <= Date.now() + skewMs) {
  throw new Error(
    'YouTube: scheduled_at đã qua hoặc sát \"giờ chạy workflow\" (< vài giây tới). PublishAt không còn trong tương lai. Giá trị: '
      + sa
      + '. Chạy lại export để \"scheduled_at\" mới, hoặc chỉnh SCHEDULE_START/SCHEDULE_INTERVAL_HOURS trong node 2.'
    ,
  );
}
const tp = String(meta.thumbnail_path || '').trim();
if (!tp) {
  throw new Error(
    'YouTube: thiếu thumbnail_path — cần file ảnh để upload thumbnail (và Studio/COPPA). Kiểm tra session + export.'
    ,
  );
}
return item;

// Sau 8c, Read File thường chỉ giữ binary vừa đọc → mất video `data`. Gộp lại trước khi upload.
const item = $input.item;
const from8 = $('8 Check read OK').item;
const data = from8?.binary?.data;
const thumb = item.binary?.thumbnail;
if (!data) {
  throw new Error(
    'Thiếu binary.data (video) sau 8c — kiểm tra 7 Read video, video_path, volume Docker/N8N_RESTRICT_FILE_ACCESS_TO.'
    ,
  );
}
if (!thumb) {
  throw new Error('Thiếu binary.thumbnail sau 8c — kiểm tra thumbnail_path và file ảnh.');
}
item.binary = { data, thumbnail: thumb };
item.json = from8?.json ?? item.json;
return item;

const raw = $('6b Carry job → Read').item?.json;
const job =
  raw != null && typeof raw === 'object' && !Array.isArray(raw) ? { ...raw } : {};
const it = $input.item;
const j = it.json || {};
const e = j.error != null ? j.error : it.error;
const msg =
  e != null
    ? (typeof e === 'string' ? e : JSON.stringify(e).slice(0, 600))
    : String(j.message || it.message || 'YouTube upload failed');
return {
  json: {
    ...job,
    youtube_upload_failed: true,
    youtube_error: String(msg || 'YouTube upload failed'),
  },
  binary: {},
};

const item = $input.item;
const j = item.json || {};
const meta = $('6b Carry job → Read').item?.json || {};
if (j.error) {
  throw new Error('YouTube API: ' + JSON.stringify(j.error).slice(0, 800));
}
const id =
  j.id || j.uploadId || j.video_id || j.videoId || j.data?.id || j.data?.uploadId;
if (!id) {
  throw new Error(
    'YouTube: no video id (expected id/uploadId/video_id): ' + JSON.stringify(j).slice(0, 800),
  );
}
item.json = { ...meta, ...j, id: String(id) };
const thumb = $('8d Gộp video và thumbnail').item?.binary?.thumbnail;
if (!thumb) {
  throw new Error(
    'YouTube: thiếu binary thumbnail (lấy từ 8d). Node upload có thể đã bỏ binary — kiểm tra 8c/8d.'
    ,
  );
}
let sz = 0;
if (thumb.fileSize != null && thumb.fileSize !== undefined) {
  sz = Number(thumb.fileSize);
} else if (thumb.data) {
  sz = Buffer.from(String(thumb.data), 'base64').length;
}
if (sz > 2097152) {
  throw new Error('YouTube thumbnail: file > 2MB — API sẽ từ chối.');
}
item.binary = { thumbnail: thumb };
return item;

const item = $input.item;
const raw = item.json || {};
const sc = Number(raw.statusCode ?? raw.status ?? 0);
if (!raw.error && (sc === 204 || sc === 205)) {
  return item;
}
if (!raw.error && sc >= 200 && sc < 300) {
  const b = raw.body;
  if (b === '' || b === null || b === undefined) {
    return item;
  }
  if (typeof b === 'string' && !String(b).trim()) {
    return item;
  }
}
function tryParse(s) {
  if (typeof s !== 'string' || !s.trim()) return null;
  try {
    return JSON.parse(s);
  } catch {
    return null;
  }
}
function unwrapApiPayload(r) {
  if (!r || typeof r !== 'object') return {};
  const buckets = [
    r,
    typeof r.body === 'string' ? tryParse(r.body) : r.body,
    typeof r.data === 'string' ? tryParse(r.data) : r.data,
  ].filter((x) => x != null && typeof x === 'object');
  for (const o of buckets) {
    if (o.error) return o;
    if (o.snippet?.thumbnails || o.thumbnails || (Array.isArray(o.items) && o.items[0]?.snippet)) {
      return o;
    }
  }
  return buckets[0] || r;
}
const THUMB_KEYS = new Set([
  'default',
  'medium',
  'high',
  'standard',
  'maxres',
  'hqdefault',
  'mqdefault',
  'sddefault',
]);
function isYoutubeThumbBlock(o) {
  if (!o || typeof o !== 'object') return false;
  const ks = Object.keys(o);
  if (!ks.some((k) => THUMB_KEYS.has(k))) return false;
  for (const k of ks) {
    if (!THUMB_KEYS.has(k)) continue;
    const v = o[k];
    if (v && typeof v === 'object' && typeof v.url === 'string') return true;
  }
  return false;
}
function walkThumbnails(o, depth) {
  if (!o || typeof o !== 'object' || depth > 12) return null;
  if (isYoutubeThumbBlock(o)) return o;
  if (Array.isArray(o)) {
    for (const el of o) {
      const t = walkThumbnails(el, depth + 1);
      if (t) return t;
    }
    return null;
  }
  for (const k of Object.keys(o)) {
    const t = walkThumbnails(o[k], depth + 1);
    if (t) return t;
  }
  return null;
}
const j = unwrapApiPayload(raw);
if (j.error) {
  throw new Error('YouTube thumbnail API: ' + JSON.stringify(j.error).slice(0, 900));
}
let thumbs =
  j.snippet?.thumbnails
  || j.thumbnails
  || (Array.isArray(j.items) && j.items[0]?.snippet?.thumbnails);
if (!thumbs || typeof thumbs !== 'object' || Object.keys(thumbs).length === 0) {
  thumbs = walkThumbnails(j, 0);
}
if (!thumbs || typeof thumbs !== 'object' || Object.keys(thumbs).length === 0) {
  if (!j.error && sc >= 200 && sc < 300) {
    return item;
  }
  const preview =
    typeof j === 'string' ? j.slice(0, 200) : JSON.stringify(j).slice(0, 500);
  throw new Error(
    'YouTube thumbnail: không đọc được object thumbnails từ phản hồi HTTP (body có thể là string chưa parse, hoặc cấu trúc khác). Gợi ý: xem raw JSON node 10b. Preview: '
      + preview
    ,
  );
}
return item;

const t = $('10 Check YouTube OK').item?.json;
const j = t != null && typeof t === 'object' && !Array.isArray(t) ? t : {};
return { json: j, binary: {} };

const cur = $input.item;
const idx =
  typeof $input.itemIndex === 'number' && !Number.isNaN($input.itemIndex)
    ? $input.itemIndex
    : 0;
let splitRows = [];
let sixbRows = [];
try {
  splitRows = $('5 Split jobs (+ giữ config)').all();
} catch {
  splitRows = [];
}
try {
  sixbRows = $('6b Carry job → Read').all();
} catch {
  sixbRows = [];
}
let j5 = splitRows[idx]?.json;
if (!j5 && splitRows.length === 0) {
  if (idx !== 0) {
    throw new Error('12b: thiếu .all() cho Split jobs — không ghép đúng job.');
  }
  j5 = $('5 Split jobs (+ giữ config)').first()?.json;
}
let j6b = sixbRows[idx]?.json;
if (!j6b && sixbRows.length === 0) {
  if (idx !== 0) {
    throw new Error('12b: thiếu .all() cho 6b — không ghép đúng job.');
  }
  j6b = $('6b Carry job → Read').first()?.json;
}
const base = {
  ...(j5 && typeof j5 === 'object' ? j5 : {}),
  ...(j6b && typeof j6b === 'object' ? j6b : {}),
};
const j = cur.json && typeof cur.json === 'object' ? cur.json : {};
const merged = { ...base, ...j };
const vid = String(merged.id || merged.youtube_remote_id || '').trim();
if (vid) merged.id = vid;
const p = String(merged.video_path || '').trim();
if (!p) {
  throw new Error(
    'Missing video_path before Facebook (index=' + idx + '). session=' + String(merged.session_name || '?')
    ,
  );
}
merged.video_path = p.split(String.fromCharCode(92)).join('/');
return { json: merged, binary: cur.binary };

const j = $input.item.json || {};
return {
  json: {
    skipped_facebook: true,
    session_name: j.session_name,
    session_folder: j.session_folder,
    note: 'Đã có posted_facebook.json — không upload lại.',
  },
  binary: {},
};

const item = $input.item;
if (item.json.error) {
  throw new Error('Read video (Facebook): ' + String(item.json.error));
}
if (!item.binary?.data) {
  throw new Error('Read video (Facebook): missing binary.data');
}
return item;

const j = $input.item.json;
if (j.error) {
  throw new Error('Facebook Graph: ' + JSON.stringify(j.error).slice(0, 800));
}
if (!j.id) {
  throw new Error('Facebook: no id in response: ' + JSON.stringify(j).slice(0, 800));
}
return $input.item;
